class ExamRoom {
public:
    int n;
    set<int> seats;

    ExamRoom(int n) : n(n) {}

    int seat() {
        if (seats.empty()) {
            seats.insert(0);
            return 0;
        }

        int maxDist = *seats.begin();
        int prev = -1;
        int res = 0;

        for (int seat : seats) {
            if (prev != -1) {
                int dist = (seat - prev) / 2;
                if (dist > maxDist) {
                    maxDist = dist;
                    res = prev + dist;
                }
            }
            prev = seat;
        }

        int distToEnd = n - 1 - *seats.rbegin();
        if (distToEnd > maxDist) {
            res = n - 1;
        }

        seats.insert(res);
        return res;
    }

    void leave(int p) {
        seats.erase(p);
    }
};

